import{_ as t,W as n,X as s,Y as o,Z as e}from"./framework-91490e6a.js";const _="/assets/images/china_house.jpeg",l={},a=e("p",null,"之前就从网友口中听闻，天津除了天津之眼没啥好玩的。但是这次自己走下来，本来想最后去天津之眼的，结果因为下雨没去成。但是有一说一，天津的景点还是很多的，它们自己也很重视，走在路上也会有很多路牌标示前往哪些景区还要多远，甚至有观光巴士。",-1),c=e("figure",null,[e("img",{src:_,alt:"瓷房子",tabindex:"0",loading:"lazy"}),e("figcaption",null,"瓷房子")],-1),i=e("p",null,"天津的公共交通不是很完善，没有集成到支付宝，而且各个景区之间也没有公共交通，我基本都是靠步行，但是还是很便宜的，从市区坐到滨海机场只要¥3.2。",-1),r=e("p",null,"天津令人印象比较深的特色有两个，一个是相声，走在景点（比如津门故里）时便能听到多种相声，也可以特意去听，虽然我没去。另一个是孙悟空，走在街上你可以看到很多打扮成孙悟空的人，我一开始并不懂，因为他们并不说话，直到我遇到了一只主动找我握手的孙悟空。跟着他的手势我给他拍了照并且合了影，到了最后他亮出卡片——他是残疾人，靠打扮成孙悟空与人照相赚钱，我便终于明白他们为什么不说话了。我付了这¥20，他也双手合十表示出感谢。",-1),d=e("p",null,"总之，我的天津之旅只有半天，最后结束在单人吃酒楼之中。下一站，日本！",-1);function u(m,p){return n(),s("div",null,[a,c,o(" more "),i,r,d])}const f=t(l,[["render",u],["__file","TravelNotes_Tianjin.html.vue"]]);export{f as default};
